use std::num::ParseIntError;

fn total_cost(item_quantity: &str) -> Result<i32, ParseIntError> {
    let processing_fee = 1;
    let cost_per_item = 5;
    let qty = item_quantity.parse::<i32>()?;
    Ok(qty * cost_per_item + processing_fee)
}

fn main() {
    let mut tokens = 100;
    let pretzel_cost = match total_cost("5") {
        Ok(cost) => cost,
        Err(e) => {
            println!("Error: {e}");
            return;
        }
    };
    tokens -= pretzel_cost;
    println!("You have {tokens} tokens left.");
}
